131→        /// <summary>
132→        /// UpdateEndPointInfoV3Async
133→        /// </summary>
134→        /// <returns>task</returns>
135→        public async Task UpdateEndPointInfoV3Async()
136→        {
137→            var lastUpdateTime = DateTime.UtcNow;
138→            this.endpointUpdater.InitSKUList();
139→
140→            using (var transaction = this.unitOfCodeX.BeginTransaction())
141→            {
142→                try
143→                {
144→                    var modelScaleSets = await this.mssUpdater.GetModelScaleSetsAsync();
145→                    this.logger.LogInformationEx($"MSS 1.Get [{lastUpdateTime}]: [{modelScaleSets.Count()}]");
146→                    modelScaleSets.ToList().ForEach(mss => this.logger.LogInformationEx($"MSS 1.Get [{lastUpdateTime}]: Region: [{mss.Key}], ModelScaleSet: [{mss.Value}]"));
147→
148→                    var mpcpReservationsProm = await this.mssUpdater.GetMpcmReservations("PROM");
149→                    this.logger.LogInformationEx($"MPCM 2a.Get PROM [{lastUpdateTime}]: [{mpcpReservationsProm.Count()}]");
150→                    mpcpReservationsProm.ToList().ForEach(res => this.logger.LogInformationEx($"MPCM 2a.Get PROM [{lastUpdateTime}]: Region: [{res.Key}], MpcmReservation: [{res.Value}]"));
151→
152→                    var mpcpReservationsPromIB = await this.mssUpdater.GetMpcmReservations("PROM IB");
153→                    this.logger.LogInformationEx($"MPCM 2b.Get PROM IB [{lastUpdateTime}]: [{mpcpReservationsPromIB.Count()}]");
154→                    mpcpReservationsPromIB.ToList().ForEach(res => this.logger.LogInformationEx($"MPCM 2b.Get PROM IB [{lastUpdateTime}]: Region: [{res.Key}], MpcmReservation: [{res.Value}]"));
155→
156→                    var mpcpReservations = this.mssUpdater.MergeMpcmReservations(mpcpReservationsProm, mpcpReservationsPromIB);
157→                    this.logger.LogInformationEx($"MPCM 2c.Merged [{lastUpdateTime}]: [{mpcpReservations.Count()}]");
158→                    mpcpReservations.ToList().ForEach(res => this.logger.LogInformationEx($"MPCM 2c.Merged [{lastUpdateTime}]: Region: [{res.Key}], MpcmReservation: [{res.Value}]"));
159→
160→                    var modelPools = await this.mssUpdater.GetModelPoolInfoAsync();
161→                    this.logger.LogInformationEx($"ModelPool 3.Get [{lastUpdateTime}]: [{modelPools.Count()}]");
162→                    modelPools.ToList().ForEach(pool => this.logger.LogInformationEx($"ModelPool 3.Get [{lastUpdateTime}]: Region: [{pool.Key}], ModelPool: [{pool.Value}]"));
163→
164→                    this.mssUpdater.UpdateModelScaleSets(modelScaleSets, lastUpdateTime);
165→                    this.logger.LogInformationEx($"MSS 1.Update {lastUpdateTime}");
166→
167→                    this.mssUpdater.UpdateMPCPReservations(mpcpReservations, lastUpdateTime);
168→                    this.logger.LogInformationEx($"MPCM 2.Update {lastUpdateTime}");
169→                    this.mssUpdater.UpdateModelPoolInfo(modelPools, lastUpdateTime);
170→                    this.logger.LogInformationEx($"ModelPool 3.Update {lastUpdateTime}");
171→
172→                    var modelScaleSetsV2 = await this.mssUpdater.GetModelScaleSetsWithContinuationTokenAsync();
173→                    this.logger.LogInformationEx($"MSS 1b.GetWithContinuationToken [{lastUpdateTime}]: [{modelScaleSetsV2.Count()}]");
174→                    this.mssUpdater.UpdateModelScaleSetsV2(modelScaleSetsV2, lastUpdateTime);
175→                    this.logger.LogInformationEx($"MSS 1b.UpdateV2 {lastUpdateTime}");
176→
177→                    var updatedEPs = new List<EndPointInfo>();
178→                    var endpointToLoadBalancerStatus = await this.endpointUpdater.GetLoadBalancerDataAsync().ConfigureAwait(false);
179→                    updatedEPs.AddRange(await this.endpointUpdater.UpdateEndPointStatus2Async(lastUpdateTime, endpointToLoadBalancerStatus).ConfigureAwait(false));
180→                    this.logger.LogInformationEx("BinhuTest 1");
181→                    this.logger.LogInformationEx("UpdateEndPointStatus2Async is done");
182→                    updatedEPs.AddRange(await this.endpointUpdater.UpdateAOAIEndPointStatus2Async(lastUpdateTime, endpointToLoadBalancerStatus).ConfigureAwait(false));
183→                    this.logger.LogInformationEx("UpdateAOAIEndPointStatus2Async is done");
184→                    this.endpointUpdater.RemoveNonUpdatedEndpointStatus2(lastUpdateTime, updatedEPs);
185→                    this.logger.LogInformationEx("RemoveNonUpdatedEndpointStatus2 is done");
186→                    await this.endpointUpdater.UpdateRegionStatus2Async().ConfigureAwait(false);
187→                    this.logger.LogInformationEx("BinhuTest 2");
188→                    this.logger.LogInformationEx("UpdateRegionStatus2Async is done");
189→
190→                    var tasks = new List<Task>();
191→                    tasks.Add(new MDMSaver(this.unitOfCodeX, this.capacityCounter, this.logger).SaveDataAsync());
192→                    tasks.Add(new DBSaver(this.unitOfCodeX).SaveDataAsync());
193→                    this.logger.LogInformationEx("BinhuTest 3");
194→                    Task.WaitAll(tasks.ToArray());
195→
196→                    transaction.Commit();
197→                }
198→                catch (Exception e)
199→                {
200→                    this.logger.LogErrorEx("Error occurred in UpdateEndPointInfoV3Async");
201→                    this.logger.LogErrorEx(e.ToString());
202→                    transaction.Rollback();
203→                }
204→            }
205→        }
206→
207→        /// <summary>
208→        /// UpdateOveriteModelName
209→        /// </summary>
210→        /// <param name="endpointId">endpointId</param>
211→        /// <param name="modelName">modelName</param>
212→        public void UpdateModelOverwriteName(int endpointId, string modelName)
213→        {
214→            modelName = modelName.Trim();
215→            var endpoint = this.unitOfCodeX.EndpointV3Repository.Entities.Where(e => e.Id.Equals(endpointId)).FirstOrDefault();
216→            var models = this.unitOfCodeX.ModelRepository.Entities.ToList();
217→            var model = models.Where(m => m.Id.Equals(endpoint.ModelId)).FirstOrDefault();
218→            var foundModel = models.FirstOrDefault(m => m.Name.Equals(modelName, StringComparison.OrdinalIgnoreCase));
219→
220→            if (foundModel != null)
221→            {
222→                endpoint.ModelId = foundModel.Id;
223→                this.unitOfCodeX.EndpointV3Repository.Update(endpoint);
224→                this.unitOfCodeX.Save();
225→            }
226→            else
227→            {
228→                if (model.Name == Constant.UnknownModelName)
229→                {
230→                    var newModel = new Model() { Name = modelName };
231→                    this.unitOfCodeX.ModelRepository.Insert(newModel);
232→                    this.unitOfCodeX.Save();
233→                    endpoint.ModelId = newModel.Id;
234→                    this.unitOfCodeX.EndpointV3Repository.Update(endpoint);
235→                    this.unitOfCodeX.Save();
236→                }
237→                else
238→                {
239→                    model.OverwriteName = modelName;
240→                    this.unitOfCodeX.ModelRepository.Update(model);
241→                    this.unitOfCodeX.Save();
242→                }
243→            }
244→        }
