578→        {
579→            var aoaiDeployments = this.unitOfCodeX.AoaiDeploymentV3Repository.Entities.ToList();
580→            var aoaiTrafficDict = new Dictionary<string, AoaiDeploymentV3>();
581→
582→            // aoai endpoint: webxt-gpt4o-vision-lmdh100-1120-picasso,
583→            // traffic group name :oai-3e61dd0e106f4bdea7a-d8f1dd09
584→            // some aml endpoints have the same traffic group name
585→            string pattern = @"^oai-[a-f0-9-]{28}$";
586→            foreach (var aoaiDeployment in aoaiDeployments)
587→            {
588→                var rawData = JsonSerializer.Deserialize<AOAIDeployment>(aoaiDeployment.AoaiDeployment);
