590→                if (!Regex.IsMatch(trafficGroupName, pattern))
591→                {
592→                    continue;
593→                }
594→
595→                if (aoaiTrafficDict.ContainsKey(trafficGroupName))
596→                {
597→                    this.logger.LogError($"Duplicate TrafficGroupName ({trafficGroupName}) found for AOAI Deployment {aoaiDeployment.Name}");
598→                    continue;
599→                }
600→
601→                aoaiTrafficDict.Add(trafficGroupName, aoaiDeployment);
602→            }
603→
