607→        /// <summary>
608→        /// Update AOAI traffic group info.
609→        /// </summary>
610→        /// <param name="trafficGroupToUpdate">trafficGroupToUpdate</param>
611→        /// <param name="deployment">deployment</param>
612→        /// <returns>new TrafficGroup</returns>
613→        private EndpointResult.TrafficGroupInfo UpdateAoaiTrafficGroupInfo(EndpointResult.TrafficGroupInfo trafficGroupToUpdate, AoaiDeploymentV3 deployment)
614→        {
615→            var deploymentStatus = this.unitOfCodeX.AoaiDeploymentStatusV3Repository.Entities.Where((status) => status.AoaiDeploymentId == deployment.Id).FirstOrDefault();
616→
617→            string aoaiDeployment = deployment.Name;
618→            string aoaiAccount = deployment.Account;
619→            IEnumerable<string> modelNames = trafficGroupToUpdate.ModelNames;
620→            string loadBalancerType = trafficGroupToUpdate.LoadBalancerType;
621→
622→            // Deployment has fungible status and load balancer status
623→            if (!string.IsNullOrEmpty(deploymentStatus?.LoadBalancerStatus))
624→            {
625→                var deploymentLoadBalancerData = new EndpointLoadBalancerStatus();
626→                deploymentLoadBalancerData.TrafficGroupLoadBalancerStatus = JsonSerializer.Deserialize<Dictionary<string, EndpointTrafficGroupLoadBalancerStatus>>(deploymentStatus.LoadBalancerStatus);
627→
628→                // AOAI Load Balancer data includes information for this traffic group
629→                if (deploymentLoadBalancerData.TrafficGroupLoadBalancerStatus.TryGetValue(trafficGroupToUpdate.Name, out var aoaiTrafficGroupLoadBalancerData))
630→                {
631→                    modelNames = aoaiTrafficGroupLoadBalancerData.ModelNames;
632→                    loadBalancerType = aoaiTrafficGroupLoadBalancerData.LoadBalancerType;
633→                }
634→            }
635→
636→            string trafficGroupPattern = @"^oai-[a-f0-9-]{28}$";
637→            bool isMatch = !string.IsNullOrEmpty(trafficGroupToUpdate.Name) &&
638→             Regex.IsMatch(trafficGroupToUpdate.Name, trafficGroupPattern);
639→
640→            string trafficGroupExtractedName = isMatch
641→             ? aoaiDeployment.Substring(aoaiDeployment.LastIndexOf('-') + 1)
642→             : trafficGroupToUpdate.Name;
643→
644→            return trafficGroupToUpdate with
645→            {
646→                AOAIDeployment = aoaiDeployment,
647→                AOAIAccount = aoaiAccount,
648→                ModelNames = modelNames,
649→                LoadBalancerType = loadBalancerType,
650→                Name = trafficGroupExtractedName,
651→            };
652→        }
