713→        private void UpdateTrafficGroupGpuCount(List<EndpointResult.TrafficGroupInfo> trafficGroups, IEnumerable<EndpointResultRevised.TrafficGroupInfo> revisedTrafficGroups)
714→        {
715→            if (revisedTrafficGroups == null || !revisedTrafficGroups.Any())
716→            {
717→                return;
718→            }
719→
720→            for (int i = 0; i < trafficGroups.Count; i++)
721→            {
722→                var revisedTrafficGroup = revisedTrafficGroups.FirstOrDefault(g => g.AoaiDeploymentSuffix == trafficGroups[i].Name);
723→                if (revisedTrafficGroup != null)
724→                {
725→                    // Use 'with' expression to create a new record with updated UsedGPUs
726→                    trafficGroups[i] = trafficGroups[i] with { UsedGPUs = revisedTrafficGroup.UsedGPUs };
727→                }
728→            }
729→        }
730→    }
