 59→            this.aoaiClient = aoaiClient ?? throw new ArgumentNullException(nameof(aoaiClient));
 60→            this.rolePermissionService = rolePermissionService ?? throw new ArgumentNullException(nameof(rolePermissionService));
 61→            this.configSvc = configSvc ?? throw new ArgumentNullException(nameof(configSvc));
