 64→        /// <inheritdoc/>
 65→        public async Task<ValidationResult> ValidateConfigChangeSetAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
 66→        {
 67→            if (changeSet == null)
 68→            {
 69→                throw new ArgumentNullException(nameof(changeSet));
 70→            }
 71→
 72→            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
 73→            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);
 74→
 75→            if (string.IsNullOrEmpty(changeSet.Title))
 76→            {
 77→                return new ValidationResult(false, "PR Title missing");
 78→            }
 79→
 80→            if (string.IsNullOrEmpty(changeSet.Description))
 81→            {
 82→                return new ValidationResult(false, "PR Description missing");
 83→            }
 84→
 85→            if (changeSet.EndpointCreateCommands.Any(createCommand => createCommand.EndpointConfig.Weight < 0))
 86→            {
 87→                return new ValidationResult(false, "Endpoint Weight must be a non-negative number");
 88→            }
 89→
 90→            foreach (var endpointCreateCommand in changeSet.EndpointCreateCommands)
 91→            {
 92→                var url = endpointCreateCommand.EndpointConfig.URL;
 93→
 94→                // TODO: investigate how the AML url works for endpoint validation
 95→                // var validationResult = await this.ValidateDeploymentURLAsync(url);
 96→                // if (!validationResult.Result)
 97→                // {
 98→                //     return new ValidationResult(false, validationResult.ErrorMessage);
 99→                // }
100→            }
101→
102→            // Validate that all newly created GLBs have at least one quota (appid) configured
103→            var newGlbsWithoutQuotas = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
104→                .Where(glb =>
105→                    !string.IsNullOrWhiteSpace(glb.ModelName) &&
106→                    !string.IsNullOrWhiteSpace(glb.TrafficGroup) &&
107→                    !(changeSet.AppQuotaCreateCommands ?? Enumerable.Empty<AppQuotaCreateCommand>()).Any(q =>
108→                        string.Equals(q.ModelName?.Trim(), glb.ModelName?.Trim(), StringComparison.OrdinalIgnoreCase) &&
109→                        string.Equals(q.TrafficGroup?.Trim(), glb.TrafficGroup?.Trim(), StringComparison.OrdinalIgnoreCase)))
110→                .Select(glb => $"{glb.ModelName?.Trim()} / {glb.TrafficGroup?.Trim()}")
111→                .ToList();
112→
113→            if (newGlbsWithoutQuotas.Any())
114→            {
115→                return new ValidationResult(false, $"All newly created GLBs must have at least one quota (appid) configured. Missing: {string.Join(", ", newGlbsWithoutQuotas)}");
116→            }
117→
118→            var hasAppQuotaCommands = changeSet.AppQuotaCreateCommands.Any()
119→                || changeSet.AppQuotaUpdateCommands.Any()
120→                || changeSet.AppQuotaDeleteCommands.Any();
121→
122→            // Validate AppQuota commands' change values - create/delete/update quota as owners
123→            if (!userIsAdmin && hasAppQuotaCommands)
124→            {
125→                var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);
126→
127→                // GLBs being created in this changeset are treated as owned by the submitter
128→                var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
129→                    .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
130→                    .Where(key => !string.IsNullOrWhiteSpace(key))
131→                    .ToHashSet(StringComparer.OrdinalIgnoreCase);
132→
133→                var targetModelTrafficGroups = changeSet.GetAppQuotaModelTrafficGroupKeys()
134→                    .Where(key => !string.IsNullOrWhiteSpace(key))
135→                    .Distinct(StringComparer.OrdinalIgnoreCase)
136→                    .ToList();
137→
138→                var nonOwnedModelTrafficGroups = targetModelTrafficGroups
139→                    .Where(key => !ownedModelTrafficGroups.Contains(key) && !glbsBeingCreated.Contains(key))
140→                    .ToHashSet(StringComparer.OrdinalIgnoreCase);
141→
142→                if (nonOwnedModelTrafficGroups.Any())
143→                {
144→                    var appQuotas = await this.configSvc.GetPapyrusControlAppQuotasAsync();
145→
146→                    var allQuotaDeltas = new List<AppQuotaUpdateDelta>();
147→
148→                    // Handle update commands (existing logic)
149→                    var updateDeltas = changeSet.AppQuotaUpdateCommands.Select(command =>
150→                    {
151→                        var originalQuotaValue = appQuotas.FirstOrDefault(appQuota =>
152→                            (appQuota.ModelName == command.ModelName) &&
153→                            (appQuota.TrafficGroup == command.TrafficGroup) &&
154→                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
155→                        return new AppQuotaUpdateDelta(
156→                            command.ModelName,
157→                            command.TrafficGroup,
158→                            command.AppQuotaConfig.AppId,
159→                            command.AppQuotaConfig.OnlineQuota - originalQuotaValue);
160→                    });
161→
162→                    // Handle create commands (new quota = positive delta)
163→                    var createDeltas = changeSet.AppQuotaCreateCommands.Select(command =>
164→                        new AppQuotaUpdateDelta(
165→                            command.ModelName,
166→                            command.TrafficGroup,
167→                            command.AppQuotaConfig.AppId,
168→                            command.AppQuotaConfig.OnlineQuota)); // Full quota value as positive delta
169→
170→                    // Handle delete commands (removed quota = negative delta)
171→                    var deleteDeltas = changeSet.AppQuotaDeleteCommands.Select(command =>
172→                    {
173→                        var existingQuotaValue = appQuotas.FirstOrDefault(appQuota =>
174→                            (appQuota.ModelName == command.ModelName) &&
175→                            (appQuota.TrafficGroup == command.TrafficGroup) &&
176→                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
177→                        return new AppQuotaUpdateDelta(
178→                            command.ModelName,
179→                            command.TrafficGroup,
180→                            command.AppQuotaConfig.AppId,
181→                            -existingQuotaValue); // Negative delta for deletion
182→                    });
183→
184→                    // Combine all deltas
185→                    allQuotaDeltas.AddRange(updateDeltas);
186→                    allQuotaDeltas.AddRange(createDeltas);
187→                    allQuotaDeltas.AddRange(deleteDeltas);
188→
189→                    var deltasToValidate = allQuotaDeltas
190→                        .Where(delta => nonOwnedModelTrafficGroups.Contains($"{delta.ModelName}-{delta.TrafficGroup}"))
191→                        .ToList();
192→
193→                    if (deltasToValidate.Any())
194→                    {
195→                        // Quota change validation is done across all apps under the same organization within the same model name and traffic group pair.
196→                        var changeDict = deltasToValidate
197→                            .GroupBy(item => $"{item.ModelName}-{item.TrafficGroup}.{PapyrusUtils.GetOrgNameFromAppId(item.AppId)}")
198→                            .ToDictionary(
199→                                group => group.Key,
200→                                group => group.Sum(item => item.QuotaChange));
201→
202→                        foreach (var appOrganizationChange in changeDict)
203→                        {
204→                            if (appOrganizationChange.Value != 0)
205→                            {
206→                                return new ValidationResult(false, $"App Organization '{appOrganizationChange.Key}' has a non-zero quota change across all apps under this organization. Net change: {appOrganizationChange.Value / 1000}. You must balance quota additions with quota reductions within the same organization and model-traffic group.");
207→                            }
208→                        }
209→                    }
210→                }
211→            }
212→
213→            if (changeSet.ServiceAuthQuotaCreateCommands.Any() || changeSet.ServiceAuthQuotaUpdateCommands.Any())
214→            {
215→                return this.ValidateChangeSetGuids(changeSet);
216→            }
217→
218→            return new ValidationResult(true, null);
219→        }
