521→        /// <summary>
522→        /// For app quota entries where the user does not own the model traffic group,
523→        /// checks quota app ID ownership as a fallback. Returns the non-owned app IDs.
524→        /// </summary>
525→        private static List<string> GetNonOwnedQuotaAppIds(
526→            IEnumerable<(string MtgKey, string AppId)> appQuotaEntries,
527→            ISet<string> ownedModelTrafficGroups,
528→            ISet<string> glbsBeingCreated,
529→            ISet<string> ownedQuotaAppIds)
530→        {
531→            var nonOwned = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
532→
533→            foreach (var (mtgKey, appId) in appQuotaEntries)
534→            {
535→                if (string.IsNullOrWhiteSpace(appId))
536→                {
537→                    continue;
538→                }
539→
540→                // If the user owns the model traffic group, they're authorized for this entry
541→                if (!string.IsNullOrWhiteSpace(mtgKey) &&
542→                    (ownedModelTrafficGroups.Contains(mtgKey) || glbsBeingCreated.Contains(mtgKey)))
543→                {
544→                    continue;
545→                }
546→
547→                // Fall back to quota app ID ownership
548→                if (!HasOwnershipForAppId(appId, ownedQuotaAppIds))
549→                {
550→                    nonOwned.Add(appId);
551→                }
552→            }
553→
554→            return nonOwned.ToList();
555→        }
