580→        /// <summary>
581→        /// Validates that the user has owner permission for the organizations associated with the given app IDs.
582→        /// </summary>
583→        /// <param name="user">The user claims principal.</param>
584→        /// <param name="appIds">The application IDs to check organization ownership for.</param>
585→        /// <param name="userAlias">The user's alias for error messages.</param>
586→        /// <returns>A validation result indicating success or failure with appropriate error message.</returns>
587→        private async Task<ValidationResult> ValidateOrganizationOwnershipAsync(ClaimsPrincipal user, IEnumerable<string> appIds, string userAlias)
588→        {
589→            var targetAppIds = (appIds ?? Enumerable.Empty<string>())
590→                .Where(id => !string.IsNullOrWhiteSpace(id))
591→                .Distinct(StringComparer.OrdinalIgnoreCase)
592→                .ToList();
593→
594→            if (!targetAppIds.Any())
595→            {
596→                return new ValidationResult(true, null);
597→            }
598→
599→            var quotas = await this.configSvc.GetServiceQuotaAndAuthManagementAsync(userAlias);
600→            var quotaOwnersLookup = (quotas ?? new List<ServiceAuthQuotaManagement>())
601→                .GroupBy(q => q.QuotaAppId, StringComparer.OrdinalIgnoreCase)
602→                .ToDictionary(
603→                    group => group.Key,
604→                    group => group
605→                        .SelectMany(q => q.Owners ?? Enumerable.Empty<string>())
606→                        .Distinct(StringComparer.OrdinalIgnoreCase)
607→                        .ToList(),
608→                    StringComparer.OrdinalIgnoreCase);
609→
610→            var ownedAppIds = new HashSet<string>(
611→                quotaOwnersLookup.Keys
612→                    .Where(key => !string.IsNullOrWhiteSpace(key))
613→                    .Select(key => key.Trim()),
614→                StringComparer.OrdinalIgnoreCase);
615→
616→            var missingQuotas = targetAppIds
617→                .Where(appId => !HasOwnershipForAppId(appId, ownedAppIds))
618→                .ToList();
619→
620→            if (missingQuotas.Any())
621→            {
622→                var errors = new List<string>();
623→
624→                if (missingQuotas.Any())
625→                {
626→                    errors.Add($"Quotas not found or not owned: [{string.Join(", ", missingQuotas)}]");
627→                }
628→
629→                return new ValidationResult(false, string.Join(". ", errors));
630→            }
631→
632→            return new ValidationResult(true, null);
633→        }
634→
635→        private async Task<ValidationResult> ValidateDeploymentURLAsync(string url)
636→        {
637→            var urlWrapper = new DeploymentURLWrapper(url);
638→            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AML)
639→            {
640→                var exists = this.codexService.CheckEndpointInRegionExists(urlWrapper.URLTokens[0], urlWrapper.URLTokens[1]);
641→                if (!exists)
642→                {
643→                    return new ValidationResult(false, $"The following AML URL does not exist: {url}");
644→                }
645→            }
646→
647→            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AOAI)
648→            {
649→                var accountName = urlWrapper.URLTokens[0];
650→                var deploymentName = urlWrapper.URLTokens[1];
651→                var deploymentExistsResult = await this.aoaiClient.CheckAoaiDeploymentExistAsync(this.aoaiClient.SubscriptionID, this.aoaiClient.ResourceGroup, accountName, deploymentName);
652→                if (!deploymentExistsResult.Result)
653→                {
654→                    return deploymentExistsResult;
655→                }
656→            }
657→
658→            return new ValidationResult(true, "Success");
659→        }
660→    }
661→}
