230→        /// <inheritdoc/>
231→        public async Task<PapyrusPullRequest> SubmitConfigChangeSetAsync(PapyrusConfigChangeSet changeSet, string author, string authorEmail)
232→        {
233→            var jsonConfig = await this.papyrusControlConfigCache.GetJsons();
234→
235→            var configiniFile = await this.gitClient.DownloadGitFileAsStringAsync(this.papyrusEnvProps.GetAdoConfigIniUrl());
236→            var serviceQuotaRegistryList = await this.RetrieveServiceQuotaRegistryListAsync(flatten: true);
237→
238→            // replace the '|' char with "__temp__" as repace back after manipulating the file.
239→            // as the library is not able to handle this char.
240→            var configini = this.parser.Parse(configiniFile.Replace("|", "__temp__"));
241→            var submittedByAlias = string.IsNullOrWhiteSpace(authorEmail) ? string.Empty : AuthUtil.NormalizeAlias(authorEmail);
242→            var commandContext = new CommandContext(submittedByAlias);
243→            this.ExecuteCommands(changeSet.GetCommands(), jsonConfig, configini, serviceQuotaRegistryList, commandContext);
244→            var updatedServiceQuotaRegistryList = new List<ServiceQuotaRegistry>(serviceQuotaRegistryList);
245→            var jsonOptions = new JsonSerializerOptions { WriteIndented = true, NewLine = "\n", Encoder = System.Text.Encodings.Web.JavaScriptEncoder.UnsafeRelaxedJsonEscaping };
246→            string timestamp = DateTime.Now.ToFileTime().ToString();
247→            var title = string.IsNullOrEmpty(changeSet.Title) ? timestamp : changeSet.Title;
248→
249→            var prFiles = new List<PRFile>()
250→            {
251→                    new PRFile(configini.ToString().Replace("__temp__", "|"), this.papyrusEnvProps.GLBConfigGitPath),
252→                    new PRFile(
253→                        JsonSerializer.Serialize(
254→                            updatedServiceQuotaRegistryList,
255→                            new JsonSerializerOptions
256→                            {
257→                                WriteIndented = true,
258→                                Encoder = System.Text.Encodings.Web.JavaScriptEncoder.UnsafeRelaxedJsonEscaping,
259→                            }),
260→                        this.papyrusEnvProps.ServiceRegistryGitPath),
261→            };
262→
263→            // Add changed single model config json files.
264→            foreach (var fileChange in commandContext.FilesChanged)
265→            {
266→                if (fileChange.Value == PRFile.FileAction.Delete)
267→                {
268→                    // for deleted files, we only need to submit an empty file with delete action, no need to include the content in the PR.
269→                    prFiles.Add(new PRFile(string.Empty, fileChange.Key, fileChange.Value));
270→                }
271→                else
272→                {
273→                    var newFileContent = jsonConfig.SingleModelConfigJsons[fileChange.Key].ToJsonString(jsonOptions);
274→                    prFiles.Add(new PRFile(newFileContent, fileChange.Key, fileChange.Value));
275→                }
276→            }
277→
278→            var args = new PRCreationArgs
279→            {
280→                Title = $"config-json-auto-pr: {title}, by: {author}",
281→                Description = this.GeneratePRDescription(changeSet.GetCommands(), changeSet.Description),
282→                AuthorName = author,
283→                AuthorEmail = authorEmail,
284→                BranchName = $"auto/config-json-auto-pr-{timestamp}",
285→                CommitMessage = "generated commit",
286→                ReviewerIds = this.papyrusEnvProps.ReviewerIds,
287→                ReviewerAliases = changeSet.AdditionalReviewers.ToArray(),
288→                WorkItemIds = [this.papyrusEnvProps.DummyWorkItemId, .. changeSet.CustomLinkedWorkItems],
289→                ValidateWorkItemsExist = changeSet.CustomLinkedWorkItems.Any(),
290→                IsDraft = changeSet.CreateDraftPR ?? this.papyrusEnvProps.CreateDraftPRs,
291→                Files = prFiles.ToArray(),
292→            };
293→
294→            GitPullRequestWrapper adoPr;
295→            try
296→            {
297→                adoPr = await this.pullRequestClient.CreatePullRequestAsync(args);
298→            }
299→            catch (Exception ex)
300→            {
301→                this.logger.LogError(ex, "Pull request creation failed for user {Author}", author);
302→                throw new UserException($"Pull request creation failed: {ex.Message}", ex);
303→            }
304→
305→            this.logger.LogInformation("PR {PrId} created successfully by {Author}", adoPr.PullRequestId, author);
306→
307→            var prRecord = new PapyrusPullRequest()
308→            {
309→                PullRequestId = adoPr.PullRequestId,
310→                AdoOrg = this.papyrusEnvProps.AdoOrg,
311→                AdoProject = this.papyrusEnvProps.AdoProject,
312→                AdoRepo = this.papyrusEnvProps.AdoRep,
313→                Status = PullRequestStatus.Active,
314→                Owner = AuthUtil.NormalizeAlias(authorEmail),
315→                CreationDate = adoPr.CreationDate,
316→                Description = changeSet.Description,
317→                Error = string.Empty,
318→            };
319→
320→            var warnings = new List<string>();
321→
322→            if (this.papyrusEnvProps.AutoMergeEnabled && changeSet.AutoMerge && prRecord.Status == PullRequestStatus.Active)
323→            {
324→                try
325→                {
326→                    // TODO: create pr with autocomplete on to skip SetAutoCompletePullRequest call
327→                    this.pullRequestClient.SetAutoCompletePullRequest(adoPr, overwriteAutoCompleteOptions: true);
328→                    this.pullRequestClient.ApprovePullRequest(adoPr);
329→                }
330→                catch (Exception ex)
331→                {
332→                    this.logger.LogError(ex, "Auto-merge setup failed for PR {PrId}", adoPr.PullRequestId);
333→                    warnings.Add($"Auto-merge setup failed: {ex.Message}");
334→                    throw;
335→                }
336→            }
337→
338→            try
339→            {
340→                this.unitOfCodeX.PapyrusPullRequestRepository.Insert(prRecord);
341→                this.unitOfCodeX.Save();
342→            }
343→            catch (Exception ex)
344→            {
345→                this.logger.LogError(ex, "Failed to save PR record for PR {PrId}", adoPr.PullRequestId);
346→                warnings.Add($"PR record save failed: {ex.Message}");
347→                throw;
348→            }
349→
350→            if (warnings.Count > 0)
351→            {
352→                prRecord.Error = string.Join("; ", warnings);
353→            }
354→
355→            return prRecord;
356→        }
