507→        private static List<string> ParseModelClientConfigOwners(string ownersRaw)
508→        {
509→            if (string.IsNullOrWhiteSpace(ownersRaw))
510→            {
511→                return new List<string>();
512→            }
513→
514→            var trimmedOwners = ownersRaw.Trim();
515→            if (trimmedOwners.StartsWith("[", StringComparison.Ordinal))
516→            {
517→                try
518→                {
519→                    using var document = JsonDocument.Parse(trimmedOwners);
520→                    if (document.RootElement.ValueKind == JsonValueKind.Array)
521→                    {
522→                        var owners = new List<string>();
523→                        foreach (var entry in document.RootElement.EnumerateArray())
524→                        {
525→                            if (entry.ValueKind == JsonValueKind.Object)
526→                            {
527→                                if (entry.TryGetProperty("displayName", out var displayNameElement))
528→                                {
529→                                    var displayName = displayNameElement.GetString();
530→                                    if (!string.IsNullOrWhiteSpace(displayName))
531→                                    {
532→                                        owners.Add(displayName.Trim());
533→                                        continue;
534→                                    }
535→                                }
536→
537→                                if (entry.TryGetProperty("id", out var idElement))
538→                                {
539→                                    var id = idElement.GetString();
540→                                    if (!string.IsNullOrWhiteSpace(id))
541→                                    {
542→                                        owners.Add(id.Trim());
543→                                    }
544→                                }
545→
546→                                continue;
547→                            }
548→
549→                            if (entry.ValueKind == JsonValueKind.String)
550→                            {
551→                                var value = entry.GetString();
552→                                if (!string.IsNullOrWhiteSpace(value))
553→                                {
554→                                    owners.Add(value.Trim());
555→                                }
556→                            }
557→                        }
558→
559→                        return owners;
560→                    }
561→                }
562→                catch (JsonException)
563→                {
564→                    // Fall back to comma-separated parsing.
565→                }
566→            }
567→
568→            return ownersRaw
569→                .Split(',', StringSplitOptions.RemoveEmptyEntries)
570→                .Select(owner => owner.Trim())
571→                .Where(owner => !string.IsNullOrWhiteSpace(owner))
572→                .ToList();
573→        }
