742→        /// <summary>
743→        /// Retrieves owners mapped to model traffic groups from ModelClientConfig.ini.
744→        /// </summary>
745→        /// <returns>A dictionary keyed by ModelLoadBalancer section names and ModelNames entries with owners list.</returns>
746→        private async Task<IReadOnlyDictionary<string, List<string>>> RetrieveModelTrafficGroupOwnersAsync()
747→        {
748→            var ownersLookup = new Dictionary<string, List<string>>(StringComparer.OrdinalIgnoreCase);
749→            var configFile = await this.RetrieveModelClientConfigFiles();
750→            var iniData = this.parser.Parse(configFile.Replace("|", "__temp__"));
751→            if (iniData == null)
752→            {
753→                var errorMessages = string.Join("; ", this.parser.Errors.Select(e => e.Message));
754→                throw new ApplicationException($"Failed to parse model client config file. Errors: {errorMessages}");
755→            }
756→
757→            foreach (var section in iniData.Sections)
758→            {
759→                if (!section.SectionName.StartsWith("ModelLoadBalancer.", StringComparison.OrdinalIgnoreCase))
760→                {
761→                    continue;
762→                }
763→
764→                if (!section.Keys.ContainsKey("Owners"))
765→                {
766→                    continue;
767→                }
768→
769→                var ownersRaw = section.Keys["Owners"];
770→                if (string.IsNullOrWhiteSpace(ownersRaw))
771→                {
772→                    continue;
773→                }
774→
775→                var owners = ModelTrafficGroupOwnersSerializer.DeserializeOwners(ownersRaw);
776→
777→                if (!owners.Any())
778→                {
779→                    continue;
780→                }
781→
782→                void AddOwnersForKey(string key)
783→                {
784→                    if (string.IsNullOrWhiteSpace(key))
785→                    {
786→                        return;
787→                    }
788→
789→                    if (ownersLookup.TryGetValue(key, out var existingOwners))
790→                    {
791→                        ownersLookup[key] = existingOwners
792→                            .Concat(owners)
793→                            .Distinct(StringComparer.OrdinalIgnoreCase)
794→                            .ToList();
795→                    }
796→                    else
797→                    {
798→                        ownersLookup[key] = owners;
799→                    }
800→                }
801→
802→                var sectionKey = section.SectionName.Substring("ModelLoadBalancer.".Length);
803→                AddOwnersForKey(sectionKey);
804→
805→                if (section.Keys.ContainsKey("ModelNames"))
806→                {
807→                    foreach (var modelName in section.Keys["ModelNames"].Split(',', StringSplitOptions.RemoveEmptyEntries))
808→                    {
809→                        AddOwnersForKey(modelName.Trim());
810→                    }
811→                }
812→            }
813→
814→            return ownersLookup;
815→        }
