846→        /// <summary>
847→        /// Updates papyrus pull request based in status info retrieved from ADO
848→        /// </summary>
849→        /// <param name="pr">papyrus pr db entity</param>
850→        /// <param name="polledPrInfo">pr info polled from ADO</param>
851→        private void UpdatePapyrusPullRequestFromPollInfo(PapyrusPullRequest pr, GitPullRequestWrapper polledPrInfo)
852→        {
853→            if (polledPrInfo.Status == PRStatus.Completed)
854→            {
855→                pr.Status = PullRequestStatus.Completed;
856→                pr.MergeDate = polledPrInfo.MergeDate;
857→            }
858→            else if (polledPrInfo.Status == PRStatus.Abandoned)
859→            {
860→                // TODO: what if abandoned and got re-activated
861→                pr.Status = PullRequestStatus.Abandoned;
862→                pr.Error = "Pull request got manually abandoned";
863→            }
864→            else if (polledPrInfo.Status == PRStatus.Active)
865→            {
866→                if (polledPrInfo.MergeStatus == PRMergeStatus.Failure || polledPrInfo.MergeStatus == PRMergeStatus.RejectedByPolicy)
867→                {
868→                    this.pullRequestClient.AbandonPullRequest(polledPrInfo.PullRequestId);
869→                    pr.Status = PullRequestStatus.Abandoned;
870→                    pr.Error = "Pull request failed to merge, auto-abandoned";
871→                }
872→                else if (polledPrInfo.MergeStatus == PRMergeStatus.Conflicts)
873→                {
874→                    this.pullRequestClient.AbandonPullRequest(polledPrInfo.PullRequestId);
875→                    pr.Status = PullRequestStatus.Abandoned;
876→                    pr.Error = "Pull request had merge conflicts, auto-abandoned";
877→                }
878→            }
879→            else
880→            {
881→                throw new Exception($"Unsupported status {polledPrInfo.Status}");
882→            }
883→        }
