952→        /// <summary>
953→        /// Helper method to parse ConfigToPromote list into ConfigToPromoteParsed list.
954→        /// </summary>
955→        private List<ConfigToPromoteParsed> ParseConfigToPromote(List<ConfigToPromote> configToPromotes)
956→        {
957→            var parsedConfigs = new List<ConfigToPromoteParsed>();
958→
959→            // Group by commit ID and TimeToPromote.
960→            foreach (var configGroup in configToPromotes.GroupBy(c => c.CommitID + "_" + c.TimeToPromote).OrderBy(c => c.First().TimeToPromote))
961→            {
962→                var baseConfig = configGroup.First();
963→
964→                var parsedConfig = new ConfigToPromoteParsed
965→                {
966→                    CommitID = baseConfig.CommitID,
967→                    CommitUrl = this.GetCommitURL(baseConfig.CommitID),
968→                    CommitTimeUTC = this.GetCommitDateUTC(baseConfig.CommitID),
969→                    ConfigReadTimeUtc = baseConfig.ConfigReadTimeUtc,
970→                    TimeToPromote = baseConfig.TimeToPromote,
971→                };
972→
973→                foreach (var config in configGroup)
974→                {
975→                    parsedConfig.ModelConfigRows.Add(new ModelTrafficGroupConfigPromotionInfo
976→                    {
977→                        SourceFilePath = config.SourceFilePath,
978→                        ConfigRow = config.ConfigRow,
979→                        ModelTrafficGroupKey = config.ModelTrafficGroupKey,
980→                        OpType = config.OpType?.ToString() ?? string.Empty,
981→                        Description = this.SerializeJsonConfigRows(config.ConfigRow),
982→                    });
983→                }
984→
985→                parsedConfig.Description = this.SerializeJsonConfigRows(parsedConfig.ModelConfigRows.Select(c => c.ConfigRow).ToList());
986→                parsedConfigs.Add(parsedConfig);
987→            }
988→
989→            return parsedConfigs;
990→        }
